runCommand:
class DiskInfo {
    [string]$DiskNumber
    [int64]$Size
    [bool]$IsReadOnly
    [bool]$IsOnline

    DiskInfo([string]$diskNumber, [int64]$size, [bool]$IsReadOnly, [bool]$IsOnline) {
        $this.DiskNumber = $diskNumber
        $this.Size = $size
        $this.IsReadOnly = $IsReadOnly
        $this.IsOnline = $IsOnline
    }

    # Method to display disk info
    [void]DisplayDiskInfo() {
        Write-Host "Disk Number: $($this.DiskNumber)"
        Write-Host "Disk Size: $($this.Size)"
        Write-Host "IsReadOnly: $($this.IsReadOnly)"
        Write-Host "IsOnline: $($this.IsOnline)"
    }
}


function Get-DisksProperties {
    # Source of IsOnline:
    #   - Get-PhysicalDisk.OperationalStatus reflects the *physical* device state
    #     (e.g. "OK", "Lost Communication", "Degraded", "Unknown").
    #   - Get-Disk.IsOffline reflects the *logical* user-visible offline state
    #     (e.g. toggled by `diskpart offline disk` or `Set-Disk -IsOffline $true`).
    # A disk that is deliberately offlined via diskpart can still report
    # OperationalStatus = "OK" on EBS-backed EC2 instances, which hides the
    # offline state from this document. We therefore treat a disk as online
    # only when BOTH signals agree: physically "OK" AND not logically offline.
    # This strictly adds the missing logical-offline detection without changing
    # today's behavior for disks already flagged by OperationalStatus.
    $physicaldisks = Get-PhysicalDisk | Select-Object DeviceID, Size, OperationalStatus
    $logicaldisks = Get-Disk | Select-Object Number, IsOffline

    # On standard (non-Storage-Spaces) Windows configurations, and specifically
    # on EBS-backed EC2 instances, Get-PhysicalDisk.DeviceID equals
    # Get-Disk.Number. We key the logical-state map by Number and look it up
    # by DeviceID. If the lookup misses (unexpected configuration), we default
    # to treating the disk as logically online, i.e. fall back to the previous
    # OperationalStatus-only behavior so we do not introduce a regression.
    $numberToIsOffline = @{}
    foreach ($ldisk in $logicaldisks) {
        $numberToIsOffline["$($ldisk.Number)"] = [bool]$ldisk.IsOffline
    }

    $deviceToSize = @{}
    foreach ($disk in $physicaldisks) {
        $logicalIsOffline = $false
        if ($numberToIsOffline.ContainsKey("$($disk.DeviceID)")) {
            $logicalIsOffline = $numberToIsOffline["$($disk.DeviceID)"]
        }
        $deviceToSize[$disk.DeviceID] = @{
            Size = $disk.Size
            IsOnline = ($disk.OperationalStatus -eq "OK") -and (-not $logicalIsOffline)
        }
    }

    return $deviceToSize
}


function Is-DiskReadOnly {
    param(
        [Parameter(Mandatory=$true)]
        [int]$diskNumber
    )

    $diskAttrScript = @"
 select disk $diskNumber
 attributes disk
"@
    $diskAttrOutput = Invoke-Expression -Command "echo '$diskAttrScript' | diskpart"
    $diskAttrOutputLines = $diskAttrOutput -split "\n"

    if ($diskAttrOutputLines -match "Read-only\s+:\s+Yes.*") {
        return $true
    }
    return $false
}

function Get-DiskInfos {
    $devicesProperties = Get-DisksProperties

    $diskList = New-Object 'System.Collections.Generic.List[DiskInfo]'
    foreach ($deviceNumber in $devicesProperties.Keys) {
        $isReadOnly = Is-DiskReadOnly -diskNumber $deviceNumber
        $deviceSize = $devicesProperties[$deviceNumber].Size
        $isOnline = $devicesProperties[$deviceNumber].IsOnline

        $diskList.Add([DiskInfo]::new($deviceNumber, $deviceSize, $isReadOnly, $isOnline))
    }
    return $diskList
}


function NormalizeSize {
    param($sizeBytes)

    return [Math]::Ceiling($sizeBytes / 1GB)
}

# Backward compatibility: Use environment variable if available, otherwise fall back to parameter substitution
if (-not (Test-Path env:SSM_Volumes)) {
    $env:SSM_Volumes = "{{Volumes}}"
}

try {
    $userDisks = ConvertFrom-Json $env:SSM_Volumes
}

catch {
    Write-Host "Error: failed to parse Volumes:"
    exit 1
}

$systemDisks = Get-DiskInfos

if ($systemDisks.Count -ne $userDisks.Count) {
    Write-Host "Error: found #$(@($systemDisks).Count) disks, expected #$(@($userDisks).Count)"
    exit 1
}

$ret = 0

foreach ($userDisk in $userDisks) {

    $systemDisk = $null

    for ($i=0; $i -lt $systemDisks.Count; $i++) {
        if ("$(NormalizeSize $userDisk.totalStorageBytes)" -eq "$(NormalizeSize $systemDisks[$i].Size)") {
            $systemDisk = $systemDisks[$i]
            $systemDisks = $systemDisks | Where-Object { $_.DiskNumber –ne $systemDisks[$i].DiskNumber }
            break
        }
    }

    if ($systemDisk -eq $null) {
        Write-Host "Error: disk $($userDisk.deviceName) is not found"
        $ret = 1
    }

    else {
        if (-not $systemDisk.isOnline) {
            Write-Host "Error: disk $($userDisk.deviceName) is offline"
            $ret = 1
        }

        if ($systemDisk.isReadOnly) {
            Write-Host "Error: disk $($userDisk.deviceName) is read_only"
            $ret = 1
        }

        if ($systemDisk.isOnline -and (-not $systemDisk.isReadOnly)) {
            Write-Host "Success: disk $($userDisk.deviceName) is found"
        }
    }
}

$ebsRet = $ret

# ============================================
# FSx ONTAP iSCSI/MPIO Validation
# Runs after EBS checks. Skips if no FSx ONTAP postboot log found.
# ============================================

$ISCSI_POSTBOOT_LOG = Join-Path $env:SystemRoot "Temp\mgn_iscsi_postboot.log"
$ISCSI_PREFIX = "[FSx-ONTAP-Validation]"
$script:IscsiWarnings = 0
$script:IscsiFails = 0
$script:FsxOntapExpectedCount = $userDisks.Count - 1

function Write-IscsiCheckResult {
    param ([string]$Name, [string]$Status, [string]$Message)
    Write-Host "$ISCSI_PREFIX ${Name}: $Status - $Message"
    if ($Status -eq "WARNING") { $script:IscsiWarnings++ }
    if ($Status -eq "FAIL") { $script:IscsiFails++ }
}

function Get-IscsiDisksForValidation {
    if (Get-Command Get-Disk -ErrorAction SilentlyContinue) {
        try { return @(Get-Disk -ErrorAction SilentlyContinue | Where-Object { $_.BusType -eq 'iSCSI' }) }
        catch { return @() }
    }
    # Fallback for Windows 2008 R2 where Get-Disk is unavailable (requires Storage module from 2012+)
    try {
        $sessions = iscsicli SessionList 2>&1
        $count = @($sessions | Select-String "Session Id").Count
        if ($count -eq 0) { return @() }
        return @(1..$count | ForEach-Object { [PSCustomObject]@{ BusType='iSCSI'; OperationalStatus='Online' } })
    } catch { return @() }
}

# Fallback for Windows 2008 R2 where Get-Partition/Get-Volume are unavailable (requires Storage module from 2012+)
function Get-IscsiMountedVolumeCount {
    param($Disks)
    if (Get-Command Get-Partition -ErrorAction SilentlyContinue) {
        $count = 0
        foreach ($disk in $Disks) {
            try {
                foreach ($part in ($disk | Get-Partition -ErrorAction SilentlyContinue)) {
                    $vol = $part | Get-Volume -ErrorAction SilentlyContinue
                    if ($vol -and ($vol.DriveLetter -or $vol.Path)) { $count++ }
                }
            } catch {}
        }
        return $count
    }
    # Legacy: use diskpart list volume
    try {
        $listScript = "$env:TEMP\iscsi_listvol.txt"
        Set-Content -Path $listScript -Value "list volume" -Encoding ASCII
        $volOutput = diskpart /s $listScript 2>&1
        Remove-Item -Path $listScript -Force -ErrorAction SilentlyContinue
        return @($volOutput | Select-String "^\s+Volume\s+\d+" | Where-Object { $_ -notmatch 'System|Boot|Recovery' }).Count
    } catch { return 0 }
}

function Get-IscsiSessionCount {
    try {
        if (Get-Command Get-IscsiSession -ErrorAction SilentlyContinue) {
            return @(Get-IscsiSession -ErrorAction SilentlyContinue | Where-Object { $_.IsConnected }).Count
        }
        # Fallback for Windows 2008 R2 where Get-IscsiSession is unavailable (requires iSCSI module from 2012+)
        return @((iscsicli SessionList 2>&1) | Select-String "Session Id").Count
    } catch { return 0 }
}

function Test-FsxOntapPresent {
    if (Test-Path $ISCSI_POSTBOOT_LOG) {
        Write-Host "$ISCSI_PREFIX Detected FSx ONTAP postboot log: $ISCSI_POSTBOOT_LOG"
        return $true
    }
    return $false
}

function Test-MpioService {
    try { $feat = Get-WindowsFeature -Name Multipath-IO -ErrorAction SilentlyContinue }
    catch { $feat = $null }
    if (-not $feat -or -not $feat.Installed) {
        Write-IscsiCheckResult -Name "multipath_service" -Status "WARNING" -Message "MPIO feature not installed"
        return
    }
    try { $mpioDisks = Get-WmiObject -Namespace root\wmi -Class MPIO_DISK_INFO -ErrorAction SilentlyContinue }
    catch { $mpioDisks = $null }
    if ($mpioDisks) {
        Write-IscsiCheckResult -Name "multipath_service" -Status "PASS" -Message "MPIO feature installed and claiming disks"
    } else {
        Write-IscsiCheckResult -Name "multipath_service" -Status "WARNING" -Message "MPIO feature installed but not claiming any disks"
    }
}

function Test-MpioHealth {
    try { $info = Get-WmiObject -Namespace root\wmi -Class MPIO_DISK_INFO -ErrorAction SilentlyContinue }
    catch { $info = $null }
    if (-not $info) {
        Write-IscsiCheckResult -Name "multipath_health" -Status "WARNING" -Message "No MPIO disk info available"
        return
    }
    $driveInfos = @($info | ForEach-Object { $_.DriveInfo })
    if ($driveInfos.Count -eq 0) {
        Write-IscsiCheckResult -Name "multipath_health" -Status "WARNING" -Message "MPIO disks present but no drive info available"
        return
    }
    $singlePathDisks = @($driveInfos | Where-Object { $_.NumberPaths -lt 2 })
    if ($singlePathDisks.Count -gt 0) {
        Write-IscsiCheckResult -Name "multipath_health" -Status "WARNING" -Message "$($singlePathDisks.Count) MPIO disks with fewer than 2 paths"
    } else {
        Write-IscsiCheckResult -Name "multipath_health" -Status "PASS" -Message "All MPIO disks have multiple paths ($($driveInfos.Count) disks healthy)"
    }
}

function Test-IscsiDeviceCount {
    $disks = Get-IscsiDisksForValidation
    $sessionCount = Get-IscsiSessionCount
    if ($disks.Count -eq $script:FsxOntapExpectedCount) {
        Write-IscsiCheckResult -Name "device_count" -Status "PASS" -Message "Found $($disks.Count) iSCSI disks (expected $($script:FsxOntapExpectedCount))"
    } elseif ($disks.Count -gt 0) {
        Write-IscsiCheckResult -Name "device_count" -Status "FAIL" -Message "Found $($disks.Count) iSCSI disks, expected $($script:FsxOntapExpectedCount) (active iSCSI sessions: $sessionCount)"
    } else {
        Write-IscsiCheckResult -Name "device_count" -Status "FAIL" -Message "No iSCSI disks found (expected $($script:FsxOntapExpectedCount), active iSCSI sessions: $sessionCount)"
    }
}

function Test-IscsiVolumeMounts {
    $disks = Get-IscsiDisksForValidation
    if ($disks.Count -eq 0) {
        $sessionCount = Get-IscsiSessionCount
        Write-IscsiCheckResult -Name "volume_mounts" -Status "FAIL" -Message "No iSCSI disks found (active iSCSI sessions: $sessionCount). Check iSCSI target connectivity (port 3260) and security groups"
        return
    }
    $online = @($disks | Where-Object { $_.OperationalStatus -eq 'Online' })
    if ($online.Count -eq 0) {
        Write-IscsiCheckResult -Name "volume_mounts" -Status "FAIL" -Message "$($disks.Count) iSCSI disks found but none are online. Use diskpart to check disk status and bring disks online"
        return
    }
    $mountedCount = Get-IscsiMountedVolumeCount -Disks $online
    if ($mountedCount -gt 0) {
        if ($mountedCount -lt $disks.Count) {
            Write-IscsiCheckResult -Name "volume_mounts" -Status "FAIL" -Message "Only $mountedCount of $($disks.Count) iSCSI disks have mounted volumes. Check disk partitions and drive letter assignments"
        } else {
            $mpioActive = $false
            try { if (Get-WmiObject -Namespace root\wmi -Class MPIO_DISK_INFO -ErrorAction SilentlyContinue) { $mpioActive = $true } } catch {}
            $sessionCount = Get-IscsiSessionCount
            if (-not $mpioActive -and $sessionCount -gt 1) {
                Write-IscsiCheckResult -Name "volume_mounts" -Status "FAIL" -Message "Multiple iSCSI paths ($($disks.Count) disks, $sessionCount sessions) without MPIO - same LUNs visible as duplicate block devices. Data corruption risk"
            } else {
                Write-IscsiCheckResult -Name "volume_mounts" -Status "PASS" -Message "$mountedCount iSCSI volumes online with mount points"
            }
        }
    } else {
        Write-IscsiCheckResult -Name "volume_mounts" -Status "FAIL" -Message "iSCSI disks online ($($online.Count)) but no volumes with drive letters or mount points. Disks may not be partitioned or formatted"
    }
}

# Run FSx ONTAP validation if indicators present
if (Test-FsxOntapPresent) {
    Write-Host "$ISCSI_PREFIX === FSx ONTAP iSCSI/MPIO Validation Started ==="
    Test-MpioService
    Test-MpioHealth
    Test-IscsiDeviceCount
    Test-IscsiVolumeMounts

    if ($script:IscsiFails -gt 0) {
        Write-Host "$ISCSI_PREFIX overall: FAIL ($($script:IscsiFails) failures, $($script:IscsiWarnings) warnings)"
        Write-Host "$ISCSI_PREFIX Troubleshooting guide: https://docs.aws.amazon.com/mgn/latest/ug/fsx-ontap-troubleshooting.html#fsx-iscsi-troubleshooting"
        exit 1
    } elseif ($script:IscsiWarnings -gt 0) {
        Write-Host "$ISCSI_PREFIX overall: WARNING ($($script:IscsiWarnings) warnings)"
        Write-Host "$ISCSI_PREFIX Troubleshooting guide: https://docs.aws.amazon.com/mgn/latest/ug/fsx-ontap-troubleshooting.html#fsx-iscsi-troubleshooting"
    } else {
        Write-Host "$ISCSI_PREFIX overall: PASS"
    }
} else {
    Write-Host "$ISCSI_PREFIX No FSx ONTAP indicators found - skipping iSCSI validation"
}

exit $ebsRet
